func NewWalkway(cfg WalkwayConfig) *Walkway {
	if cfg.Fs == nil {
		panic("fs must be set")
	}

	if cfg.PathParser == nil {
		cfg.PathParser = media.DefaultPathParser
	}

	logger := cfg.Logger
	if logger == nil {
		logger = loggers.NewDefault()
	}

	return &Walkway{
		cfg:	cfg,
		logger:	logger,
	}
}
